    question: "Demonstrate polymorphism with abstract methods.",
    mathSolution: "Abstract methods must be overridden in derived classes.",
    codeSolution: "using System;\n\nabstract class Shape\n{\n    public abstract double GetArea();\n    public abstract double GetPerimeter();\n}\n\nclass Circle : Shape\n{\n    public double Radius { get; set; }\n    \n    public Circle(double radius)\n    {\n        Radius = radius;\n    }\n    \n    public override double GetArea()\n    {\n        return Math.PI * Radius * Radius;\n    }\n    \n    public override double GetPerimeter()\n    {\n        return 2 * Math.PI * Radius;\n    }\n}\n\nclass Rectangle : Shape\n{\n    public double Width { get; set; }\n    public double Height { get; set; }\n    \n    public Rectangle(double width, double height)\n    {\n        Width = width;\n        Height = height;\n    }\n    \n    public override double GetArea()\n    {\n        return Width * Height;\n    }\n    \n    public override double GetPerimeter()\n    {\n        return 2 * (Width + Height);\n    }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        Shape[] shapes = { new Circle(5), new Rectangle(4, 6) };\n        \n        foreach (Shape shape in shapes)\n        {\n            Console.WriteLine($\"{shape.GetType().Name} - Area: {shape.GetArea():F2}, Perimeter: {shape.GetPerimeter():F2}\");\n        }\n    }\n}",
    hint: "Abstract methods force derived classes to provide implementation.",
