    question: "Demonstrate polymorphism with method parameters using base class type.",
    mathSolution: "Base class parameters accept derived objects.",
    codeSolution: "using System;\n\nclass Employee\n{\n    public string Name { get; set; }\n    \n    public virtual double CalculateBonus(double salary)\n    {\n        return salary * 0.05;\n    }\n}\n\nclass Manager : Employee\n{\n    public override double CalculateBonus(double salary)\n    {\n        return salary * 0.15;\n    }\n}\n\nclass Developer : Employee\n{\n    public override double CalculateBonus(double salary)\n    {\n        return salary * 0.10;\n    }\n}\n\nclass Payroll\n{\n    public void ProcessBonus(Employee emp, double salary)\n    {\n        double bonus = emp.CalculateBonus(salary);\n        Console.WriteLine($\"{emp.Name} ({emp.GetType().Name}) - Bonus: ${bonus}\");\n    }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        Payroll payroll = new Payroll();\n        \n        Employee[] employees = \n        {\n            new Employee { Name = \"John\" },\n            new Manager { Name = \"Alice\" },\n            new Developer { Name = \"Bob\" }\n        };\n        \n        foreach (var emp in employees)\n        {\n            payroll.ProcessBonus(emp, 50000);\n        }\n    }\n}",
    hint: "Method parameters using base class enable polymorphic behavior.",
