    mathSolution: "is operator checks runtime type of object.",
    codeSolution: "using System;\n\nclass Vehicle { public string Brand { get; set; } }\nclass Car : Vehicle { public int Doors { get; set; } }\nclass Bike : Vehicle { public bool HasGear { get; set; } }\n\nclass Program\n{\n    static void Main()\n    {\n        Vehicle[] vehicles = \n        {\n            new Car { Brand = \"Toyota\", Doors = 4 },\n            new Bike { Brand = \"Yamaha\", HasGear = true },\n            new Car { Brand = \"Honda\", Doors = 2 },\n            new Vehicle { Brand = \"Generic\" }\n        };\n        \n        foreach (Vehicle vehicle in vehicles)\n        {\n            Console.Write($\"{vehicle.Brand}: \");\n            \n            if (vehicle is Car car)\n            {\n                Console.WriteLine($\"Car with {car.Doors} doors\");\n            }\n            else if (vehicle is Bike bike)\n            {\n                Console.WriteLine($\"Bike {(bike.HasGear ? \"with\" : \"without\")} gears\");\n            }\n            else\n            {\n                Console.WriteLine(\"Generic vehicle\");\n            }\n        }\n    }\n}",
