    question: "Demonstrate polymorphism using 'as' operator for safe casting.",
    mathSolution: "as operator returns null if cast fails.",
    codeSolution: "using System;\n\ninterface IPrintable\n{\n    void Print();\n}\n\nclass Document : IPrintable\n{\n    public string Content { get; set; }\n    public void Print() => Console.WriteLine($\"Printing: {Content}\");\n}\n\nclass Image : IPrintable\n{\n    public string FileName { get; set; }\n    public void Print() => Console.WriteLine($\"Printing image: {FileName}\");\n}\n\nclass Program\n{\n    static void Main()\n    {\n        object[] items = \n        {\n            new Document { Content = \"Hello World\" },\n            \"Simple string\",\n            new Image { FileName = \"photo.jpg\" },\n            12345\n        };\n        \n        foreach (object item in items)\n        {\n            // Safe casting using 'as'\n            IPrintable printable = item as IPrintable;\n            \n            if (printable != null)\n            {\n                printable.Print();\n            }\n            else\n            {\n                Console.WriteLine($\"{item.GetType().Name} is not printable\");\n            }\n        }\n    }\n}",
    hint: "as operator returns null instead of throwing exception.",
