    codeSolution: "using System;\n\ninterface IProcessor<T>\n{\n    T Process(T input);\n}\n\nclass StringProcessor : IProcessor<string>\n{\n    public string Process(string input) => input.ToUpper();\n}\n\nclass IntProcessor : IProcessor<int>\n{\n    public int Process(int input) => input * input;\n}\n\nclass DoubleProcessor : IProcessor<double>\n{\n    public double Process(double input) => Math.Sqrt(input);\n}\n\nclass Program\n{\n    static void Main()\n    {\n        IProcessor<string> stringProc = new StringProcessor();\n        IProcessor<int> intProc = new IntProcessor();\n        IProcessor<double> doubleProc = new DoubleProcessor();\n        \n        Console.WriteLine($\"'hello' -> {stringProc.Process(\"hello\")}\");\n        Console.WriteLine($\"5 -> {intProc.Process(5)}\");\n        Console.WriteLine($\"16 -> {doubleProc.Process(16)}\");\n    }\n}",
    hint: "Generic interfaces enable polymorphic processing across types.",
